classdef RpcSymmetricFeatureAdjustment
    %RPCSYMMETRICFEATUREADJUSTMENT Robust overview RPC-3 alignment.
    %
    % The fit uses matched natural-image features only as sparse tie points.
    % Its loss is the bidirectional distance to the exact RPC height
    % trajectory over the supplied HAE samples. The symmetric gauge applies
    % [dx,dy,theta] to the reference and its negative to the moving camera,
    % so neither image is held fixed. Along-trajectory correction can remain
    % coupled to height and is reported through conditioning/residuals.
    %
    % Traceability: algo/main.tex Eqs. (1)-(2), (52)-(55), and (77)-(78);
    % long-range workplan R1 recovery milestone; D074.

    methods (Static)
        function result = estimateFromImages(reference, moving, ...
                referenceImageCamera, movingImageCamera, ...
                heightSamplesHAEMetres, options)
            arguments
                reference (:, :) {mustBeNumeric, mustBeReal, mustBeNonempty}
                moving (:, :) {mustBeNumeric, mustBeReal, mustBeNonempty}
                referenceImageCamera (1, 1) RpcImageWindowCamera
                movingImageCamera (1, 1) RpcImageWindowCamera
                heightSamplesHAEMetres (1, :) double ...
                    {mustBeFinite, mustBeStrictlyIncreasing}
                options.ReferenceValid (:, :) logical ...
                    {mustMatchImageSize(options.ReferenceValid, reference)} ...
                    = true(size(reference))
                options.MovingValid (:, :) logical ...
                    {mustMatchImageSize(options.MovingValid, moving)} ...
                    = true(size(moving))
                options.MaximumFeatures (1, 1) double ...
                    {mustBeFinite, mustBeInteger, mustBePositive, ...
                    mustBeAtMost250} = 250
                options.MinimumMatches (1, 1) double ...
                    {mustBeFinite, mustBeInteger, ...
                    mustBeGreaterThanOrEqual(options.MinimumMatches, 6)} = 12
                options.MetricThreshold (1, 1) double ...
                    {mustBeFinite, mustBePositive} = 500
                options.MaximumRatio (1, 1) double ...
                    {mustBeFinite, mustBeGreaterThan(options.MaximumRatio, 0), ...
                    mustBeLessThanOrEqual(options.MaximumRatio, 1)} = 0.8
                options.MatchThreshold (1, 1) double ...
                    {mustBeFinite, mustBePositive} = 100
                options.MaximumInitialResidualPixels (1, 1) double ...
                    {mustBeFinite, mustBePositive} = 64
                options.InlierThresholdPixels (1, 1) double ...
                    {mustBeFinite, mustBePositive} = 2
                options.HuberThresholdPixels (1, 1) double ...
                    {mustBeFinite, mustBePositive} = 2
                options.MaximumIterations (1, 1) double ...
                    {mustBeFinite, mustBeInteger, mustBePositive} = 12
            end

            if exist("detectSURFFeatures", "file") ~= 2 ...
                    || exist("extractFeatures", "file") ~= 2 ...
                    || exist("matchFeatures", "file") ~= 2
                error("RpcSymmetricFeatureAdjustment:ToolboxUnavailable", ...
                    "Feature adjustment requires Computer Vision Toolbox.");
            end
            r = single(reference);
            m = single(moving);
            r(~options.ReferenceValid) = 0;
            m(~options.MovingValid) = 0;
            rp = detectSURFFeatures(r, ...
                MetricThreshold=options.MetricThreshold);
            mp = detectSURFFeatures(m, ...
                MetricThreshold=options.MetricThreshold);
            rp = RpcSymmetricFeatureAdjustment.validPoints( ...
                rp, options.ReferenceValid);
            mp = RpcSymmetricFeatureAdjustment.validPoints( ...
                mp, options.MovingValid);
            rp = selectUniform(rp, min(options.MaximumFeatures, rp.Count), ...
                size(reference));
            mp = selectUniform(mp, min(options.MaximumFeatures, mp.Count), ...
                size(moving));
            [rf, rp] = extractFeatures(r, rp);
            [mf, mp] = extractFeatures(m, mp);
            pairs = matchFeatures(rf, mf, Unique=true, ...
                MaxRatio=options.MaximumRatio, ...
                MatchThreshold=options.MatchThreshold);
            if size(pairs, 1) < options.MinimumMatches
                error("RpcSymmetricFeatureAdjustment:InsufficientMatches", ...
                    "Only %d feature pairs survived; at least %d are required.", ...
                    size(pairs, 1), options.MinimumMatches);
            end

            rWorking = double(rp(pairs(:, 1)).Location);
            mWorking = double(mp(pairs(:, 2)).Location);
            rNative = referenceImageCamera.workingToNative(rWorking);
            mNative = movingImageCamera.workingToNative(mWorking);
            estimate = RpcSymmetricFeatureAdjustment.estimateFromMatches( ...
                rNative, mNative, ...
                RpcSymmetricFeatureAdjustment.nativeBase( ...
                referenceImageCamera), ...
                RpcSymmetricFeatureAdjustment.nativeBase(movingImageCamera), ...
                heightSamplesHAEMetres, ...
                MinimumMatches=options.MinimumMatches, ...
                MaximumInitialResidualPixels= ...
                options.MaximumInitialResidualPixels, ...
                InlierThresholdPixels=options.InlierThresholdPixels, ...
                HuberThresholdPixels=options.HuberThresholdPixels, ...
                MaximumIterations=options.MaximumIterations);
            result = estimate;
            result.Detector = "SURF";
            result.MaximumFeaturesPerImage = options.MaximumFeatures;
            result.ReferenceDetectedCount = rp.Count;
            result.MovingDetectedCount = mp.Count;
            result.MatchedPairCount = size(pairs, 1);
            result.ReferenceWorkingPointsXY = rWorking;
            result.MovingWorkingPointsXY = mWorking;
            result.ReferenceNativePointsXY = rNative;
            result.MovingNativePointsXY = mNative;
            result.ReferenceFeatureFactor = ...
                referenceImageCamera.DownsampleFactor;
            result.MovingFeatureFactor = ...
                movingImageCamera.DownsampleFactor;
        end

        function result = estimateFromMatches(referenceNativeXY, ...
                movingNativeXY, referenceCamera, movingCamera, ...
                heightSamplesHAEMetres, options)
            arguments
                referenceNativeXY (:, 2) double {mustBeFinite, mustBeReal}
                movingNativeXY (:, 2) double ...
                    {mustBeFinite, mustBeReal, ...
                    mustHaveSameRows(movingNativeXY, referenceNativeXY)}
                referenceCamera (1, 1) Rpc00bCamera
                movingCamera (1, 1) Rpc00bCamera
                heightSamplesHAEMetres (1, :) double ...
                    {mustBeFinite, mustBeStrictlyIncreasing}
                options.MinimumMatches (1, 1) double ...
                    {mustBeFinite, mustBeInteger, ...
                    mustBeGreaterThanOrEqual(options.MinimumMatches, 6)} = 12
                options.MaximumInitialResidualPixels (1, 1) double ...
                    {mustBeFinite, mustBePositive} = 64
                options.InlierThresholdPixels (1, 1) double ...
                    {mustBeFinite, mustBePositive} = 2
                options.HuberThresholdPixels (1, 1) double ...
                    {mustBeFinite, mustBePositive} = 2
                options.MaximumIterations (1, 1) double ...
                    {mustBeFinite, mustBeInteger, mustBePositive} = 12
                options.TranslationPriorSigmaPixels (1, 1) double ...
                    {mustBeFinite, mustBePositive} = 100
                options.RotationPriorSigmaRadians (1, 1) double ...
                    {mustBeFinite, mustBePositive} = pi / 180
                options.FiniteDifferenceTranslationPixels (1, 1) double ...
                    {mustBeFinite, mustBePositive} = 0.05
                options.FiniteDifferenceRotationRadians (1, 1) double ...
                    {mustBeFinite, mustBePositive} = 1e-5
            end

            n = size(referenceNativeXY, 1);
            if n < options.MinimumMatches
                error("RpcSymmetricFeatureAdjustment:InsufficientMatches", ...
                    "At least %d matches are required; received %d.", ...
                    options.MinimumMatches, n);
            end
            span = range(referenceNativeXY, 1);
            if any(span < 0.05 .* [referenceCamera.ImageSize(2), ...
                    referenceCamera.ImageSize(1)])
                error("RpcSymmetricFeatureAdjustment:DegenerateDistribution", ...
                    "Matched reference features must span at least 5%% per axis.");
            end

            q = zeros(1, 3);
            [before, beforeHeight] = ...
                RpcSymmetricFeatureAdjustment.residual( ...
                q, referenceNativeXY, movingNativeXY, referenceCamera, ...
                movingCamera, heightSamplesHAEMetres);
            beforeNorm = RpcSymmetricFeatureAdjustment.normPerMatch(before);
            candidate = isfinite(beforeNorm) ...
                & beforeNorm <= options.MaximumInitialResidualPixels;
            if nnz(candidate) < options.MinimumMatches
                error("RpcSymmetricFeatureAdjustment:InsufficientEpipolarInliers", ...
                    ["Only %d matches lie within the %.3g-pixel initial " ...
                    "bidirectional trajectory gate."], nnz(candidate), ...
                    options.MaximumInitialResidualPixels);
            end

            steps = [options.FiniteDifferenceTranslationPixels, ...
                options.FiniteDifferenceTranslationPixels, ...
                options.FiniteDifferenceRotationRadians];
            prior = [options.TranslationPriorSigmaPixels, ...
                options.TranslationPriorSigmaPixels, ...
                options.RotationPriorSigmaRadians];
            objective = nan(options.MaximumIterations + 1, 1);
            objective(1) = RpcSymmetricFeatureAdjustment.objective( ...
                before(candidate, :), q, prior, ...
                options.HuberThresholdPixels);
            condition = NaN;
            iterations = 0;
            for k = 1:options.MaximumIterations
                [r, ~] = RpcSymmetricFeatureAdjustment.residual( ...
                    q, referenceNativeXY, movingNativeXY, referenceCamera, ...
                    movingCamera, heightSamplesHAEMetres);
                use = candidate & all(isfinite(r), 2);
                if nnz(use) < options.MinimumMatches
                    break
                end
                rv = reshape(r(use, :).', [], 1);
                e = RpcSymmetricFeatureAdjustment.normPerMatch(r(use, :));
                wt = min(1, options.HuberThresholdPixels ...
                    ./ max(e, realmin));
                w = repelem(wt, 4);
                j = zeros(numel(rv), 3);
                for d = 1:3
                    qt = q;
                    qt(d) = qt(d) + steps(d);
                    rt = RpcSymmetricFeatureAdjustment.residual( ...
                        qt, referenceNativeXY, movingNativeXY, ...
                        referenceCamera, movingCamera, ...
                        heightSamplesHAEMetres);
                    j(:, d) = reshape( ...
                        ((rt(use, :) - r(use, :)) ./ steps(d)).', [], 1);
                end
                jw = j .* sqrt(w);
                rw = rv .* sqrt(w);
                a = jw.' * jw + diag(1 ./ prior .^ 2);
                b = jw.' * rw + q.' ./ prior(:) .^ 2;
                condition = cond(a);
                if ~isfinite(condition) || rcond(a) < 1e-12
                    break
                end
                dq = -(a \ b).';
                dq(1:2) = max(-2, min(2, dq(1:2)));
                dq(3) = max(-0.001, min(0.001, dq(3)));
                accepted = false;
                current = RpcSymmetricFeatureAdjustment.objective( ...
                    r(use, :), q, prior, options.HuberThresholdPixels);
                for alpha = [1, 0.5, 0.25, 0.125]
                    trial = q + alpha .* dq;
                    tr = RpcSymmetricFeatureAdjustment.residual( ...
                        trial, referenceNativeXY, movingNativeXY, ...
                        referenceCamera, movingCamera, ...
                        heightSamplesHAEMetres);
                    value = RpcSymmetricFeatureAdjustment.objective( ...
                        tr(use, :), trial, prior, ...
                        options.HuberThresholdPixels);
                    if value < current
                        q = trial;
                        accepted = true;
                        break
                    end
                end
                iterations = k;
                objective(k + 1) = value;
                if ~accepted || norm(alpha .* dq ./ steps) < 1e-3
                    break
                end
            end

            [after, afterHeight] = RpcSymmetricFeatureAdjustment.residual( ...
                q, referenceNativeXY, movingNativeXY, referenceCamera, ...
                movingCamera, heightSamplesHAEMetres);
            afterNorm = RpcSymmetricFeatureAdjustment.normPerMatch(after);
            inlier = candidate & isfinite(afterNorm) ...
                & afterNorm <= options.InlierThresholdPixels;
            result = struct( ...
                "Model", "symmetric RPC-3 native image correction", ...
                "ReferenceParametersNativePixelsRadians", q, ...
                "MovingParametersNativePixelsRadians", -q, ...
                "Gauge", ...
                "equal-and-opposite native image parameters; neither camera fixed", ...
                "HeightSamplesHAEMetres", heightSamplesHAEMetres, ...
                "CandidateMask", candidate, "InlierMask", inlier, ...
                "CandidateCount", nnz(candidate), ...
                "InlierCount", nnz(inlier), ...
                "BeforeResidualXYBidirectional", before, ...
                "AfterResidualXYBidirectional", after, ...
                "BeforeResidualPixels", beforeNorm, ...
                "AfterResidualPixels", afterNorm, ...
                "BeforeBestHeightHAEMetres", beforeHeight, ...
                "AfterBestHeightHAEMetres", afterHeight, ...
                "BeforeMedianResidualPixels", median(beforeNorm(candidate)), ...
                "AfterMedianResidualPixels", median(afterNorm(candidate)), ...
                "Iterations", iterations, ...
                "NormalMatrixCondition", condition, ...
                "ObjectiveHistory", objective(1:(iterations + 1)), ...
                "Converged", nnz(inlier) >= options.MinimumMatches ...
                && isfinite(condition), ...
                "Limitation", ...
                "along-trajectory correction may remain coupled to terrain height");
        end
    end

    methods (Static, Access = private)
        function points = validPoints(points, mask)
            if points.Count == 0
                return
            end
            p = round(points.Location);
            inside = p(:, 1) >= 1 & p(:, 1) <= size(mask, 2) ...
                & p(:, 2) >= 1 & p(:, 2) <= size(mask, 1);
            index = false(points.Count, 1);
            index(inside) = mask(sub2ind(size(mask), ...
                p(inside, 2), p(inside, 1)));
            points = points(index);
        end

        function camera = nativeBase(imageCamera)
            camera = imageCamera.BaseCamera;
            if isa(camera, "RpcImageCorrectionCamera")
                camera = camera.BaseCamera;
            end
            if ~isa(camera, "Rpc00bCamera") ...
                    || camera.DownsampleFactor ~= 1
                error("RpcSymmetricFeatureAdjustment:NativeCameraRequired", ...
                    "Feature-image cameras must wrap native factor-one RPCs.");
            end
        end

        function [r, bestHeight] = residual(q, p1, p2, c1, c2, z)
            a = RpcImageCorrectionCamera(c1, q);
            b = RpcImageCorrectionCamera(c2, -q);
            n = size(p1, 1);
            l = numel(z);
            pp1 = repmat(p1, l, 1);
            pp2 = repmat(p2, l, 1);
            zz = repelem(z(:), n);
            [x1, v1] = a.imageToWorldAtHeight(pp1, zz);
            [w12, v12] = b.worldToImage(x1);
            [x2, v2] = b.imageToWorldAtHeight(pp2, zz);
            [w21, v21] = a.worldToImage(x2);
            d12 = reshape(sum((w12 - pp2) .^ 2, 2), n, l);
            d21 = reshape(sum((w21 - pp1) .^ 2, 2), n, l);
            valid = reshape(v1 & v12 & v2 & v21, n, l);
            cost = d12 + d21;
            cost(~valid) = Inf;
            [~, index] = min(cost, [], 2);
            row = (1:n).';
            linear = sub2ind([n, l], row, index);
            w12 = reshape(w12, n, l, 2);
            w21 = reshape(w21, n, l, 2);
            r = nan(n, 4);
            r(:, 1) = w12(linear) - p2(:, 1);
            r(:, 2) = w12(linear + n .* l) - p2(:, 2);
            r(:, 3) = w21(linear) - p1(:, 1);
            r(:, 4) = w21(linear + n .* l) - p1(:, 2);
            noValid = ~isfinite(cost(linear));
            r(noValid, :) = NaN;
            bestHeight = z(index).';
            bestHeight(noValid) = NaN;
        end

        function e = normPerMatch(r)
            e = sqrt(0.5 .* sum(r .^ 2, 2));
            e(~all(isfinite(r), 2)) = NaN;
        end

        function value = objective(r, q, prior, huber)
            e = RpcSymmetricFeatureAdjustment.normPerMatch(r);
            e = e(isfinite(e));
            if isempty(e)
                value = Inf;
                return
            end
            loss = 0.5 .* min(e, huber) .^ 2 ...
                + huber .* max(e - huber, 0);
            value = sum(loss) + 0.5 .* sum((q ./ prior) .^ 2);
        end
    end
end

function mustMatchImageSize(mask, image)
if ~isequal(size(mask), size(image))
    error("RpcSymmetricFeatureAdjustment:MaskSizeMismatch", ...
        "Each validity mask must match its image.");
end
end

function mustHaveSameRows(a, b)
if size(a, 1) ~= size(b, 1)
    error("RpcSymmetricFeatureAdjustment:MatchCountMismatch", ...
        "Reference and moving point arrays must have the same row count.");
end
end

function mustBeStrictlyIncreasing(z)
if numel(z) < 3 || any(diff(z) <= 0)
    error("RpcSymmetricFeatureAdjustment:InvalidHeightSamples", ...
        "Height samples must contain at least three increasing values.");
end
end

function mustBeAtMost250(value)
if value > 250
    error("RpcSymmetricFeatureAdjustment:FeatureCapExceeded", ...
        "MaximumFeatures cannot exceed 250 per image.");
end
end
